import * as React from "react"
import * as SliderPrimitive from "@radix-ui/react-slider"
import { cva } from "class-variance-authority"

import { cn } from "@/lib/utils"
import "./slider.css"

const sliderVariants = cva(
  "slider-root relative flex w-full touch-none items-center select-none h-[var(--layout-size-md)]"
)

function Slider({
  className,
  defaultValue = [0],
  ...props
}: React.ComponentProps<typeof SliderPrimitive.Root>) {
  return (
    <SliderPrimitive.Root
      data-slot="slider"
      className={cn(sliderVariants(), className)}
      defaultValue={defaultValue}
      {...props}
    >
      <SliderPrimitive.Track className="slider-track relative grow overflow-visible rounded-[var(--layout-radius-full)] h-1.5">
        <SliderPrimitive.Range className="slider-range absolute h-full rounded-[var(--layout-radius-full)]" />
      </SliderPrimitive.Track>
      <SliderPrimitive.Thumb className="slider-thumb block h-[var(--layout-size-xs)] w-[var(--layout-size-xs)] rounded-[var(--layout-radius-xs)] rotate-45 focus-visible:outline-none" />
    </SliderPrimitive.Root>
  )
}

function SliderField({
  className,
  label,
  suffix,
  value,
  onValueChange,
  onValueCommit,
  min = 0,
  max = 100,
  step = 1,
  disabled,
  ...props
}: Omit<React.ComponentProps<"div">, "value" | "onChange"> & {
  label: string
  suffix?: string
  value: number[]
  onValueChange: (value: number[]) => void
  onValueCommit?: (value: number[]) => void
  min?: number
  max?: number
  step?: number
  disabled?: boolean
}) {
  const id = React.useId()
  const [inputValue, setInputValue] = React.useState(String(value[0]))

  React.useEffect(() => {
    setInputValue(String(value[0]))
  }, [value])

  const commitInput = () => {
    const parsed = Number(inputValue)
    if (Number.isNaN(parsed)) {
      setInputValue(String(value[0]))
      return
    }
    const clamped = Math.min(max, Math.max(min, parsed))
    const newValue = [clamped]
    onValueChange(newValue)
    onValueCommit?.(newValue)
    setInputValue(String(clamped))
  }

  return (
    <div
      data-slot="slider-field"
      data-disabled={disabled || undefined}
      className={cn("flex flex-col gap-[var(--layout-gap-md)]", className)}
      {...props}
    >
      <div className="flex items-center justify-between">
        <label
          htmlFor={id}
          className={cn(
            "text-content-body font-accent slider-field-label",
            disabled ? "cursor-default" : "cursor-pointer"
          )}
        >
          {label}
        </label>
        <div className="slider-field-input-wrapper flex items-center overflow-hidden rounded-[var(--layout-radius-sm)]">
          <input
            id={id}
            type="number"
            inputMode="numeric"
            min={min}
            max={max}
            step={step}
            disabled={disabled}
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            onBlur={commitInput}
            onKeyDown={(e) => {
              if (e.key === "Enter") commitInput()
            }}
            className="slider-field-input w-12 text-center text-content-note font-accent bg-transparent border-none outline-none py-[var(--layout-padding-xs)] [appearance:textfield] [&::-webkit-inner-spin-button]:appearance-none [&::-webkit-outer-spin-button]:appearance-none"
          />
          {suffix && (
            <span className="slider-field-suffix text-content-note px-[var(--layout-padding-sm)] py-[var(--layout-padding-xs)]">
              {suffix}
            </span>
          )}
        </div>
      </div>
      <Slider
        value={value}
        onValueChange={onValueChange}
        onValueCommit={onValueCommit}
        min={min}
        max={max}
        step={step}
        disabled={disabled}
        aria-label={label}
      />
    </div>
  )
}

export { Slider, SliderField, sliderVariants }

/* ================================================================
 * SLIDER — Track, Range, Thumb & State Styles
 * Structure (flex, size, radius, rotation) lives in slider.tsx via cva.
 * Theming (colors, borders, shadows, transitions) lives here via tokens.
 * ================================================================ */

/* --------------------------------
 * Track — background
 * -------------------------------- */
.slider-track {
  background-color: transparent;
  border: var(--layout-border-thin) solid var(--border-default);
}

/* --------------------------------
 * Range — filled portion
 * -------------------------------- */
.slider-range {
  background-color: var(--background-neutral-strong-default);
}

/* --------------------------------
 * Thumb — base
 * -------------------------------- */
.slider-thumb {
  background: var(--text-fixed);
  border: var(--layout-border-thin) solid var(--border-default);
  box-shadow: var(--shadow-elevation-sm);
}

/* --------------------------------
 * Thumb — touch target (44×44px WCAG 2.5.5)
 * -------------------------------- */
.slider-thumb::before {
  content: "";
  position: absolute;
  width: 44px;
  height: 44px;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%) rotate(-45deg);
}

/* --------------------------------
 * Thumb — no focus ring on pointer interaction, only keyboard
 * -------------------------------- */
.slider-thumb:focus-visible:not(:active) {
  outline: 2px solid var(--border-selected);
  outline-offset: 2px;
}

/* --------------------------------
 * Disabled — track + range + thumb
 * -------------------------------- */
.slider-root[data-disabled] {
  pointer-events: none;
}

.slider-root[data-disabled] .slider-track,
.slider-root[data-disabled] .slider-range {
  background-color: var(--background-neutral-lighter-default);
}

.slider-root[data-disabled] .slider-thumb {
  background: var(--background-neutral-medium-default);
  border-color: transparent;
  box-shadow: none;
}

/* --------------------------------
 * Transitions
 * -------------------------------- */
@media (prefers-reduced-motion: no-preference) {
  .slider-range,
  .slider-track {
    transition: background-color 150ms ease;
  }

  .slider-thumb {
    transition: border-color 150ms ease, box-shadow 150ms ease;
  }
}

/* --------------------------------
 * Forced colors (Windows High Contrast)
 * -------------------------------- */
/* ================================================================
 * SLIDER FIELD — Label + Input wrapper
 * ================================================================ */

/* --------------------------------
 * Label
 * -------------------------------- */
.slider-field-label {
  color: var(--text-base-strong);
}

/* --------------------------------
 * Input wrapper
 * -------------------------------- */
.slider-field-input-wrapper {
  border: var(--layout-border-thin) solid var(--border-default);
}

/* --------------------------------
 * Input
 * -------------------------------- */
.slider-field-input {
  color: var(--text-base-strong);
}

/* --------------------------------
 * Suffix
 * -------------------------------- */
.slider-field-suffix {
  color: var(--text-base-moderate);
  border-left: var(--layout-border-thin) solid var(--border-default);
}

/* --------------------------------
 * Disabled — field
 * -------------------------------- */
[data-slot="slider-field"][data-disabled] .slider-field-label {
  color: var(--text-disabled);
}

[data-slot="slider-field"][data-disabled] .slider-field-input-wrapper {
  border-color: var(--border-default);
}

[data-slot="slider-field"][data-disabled] .slider-field-input,
[data-slot="slider-field"][data-disabled] .slider-field-suffix {
  color: var(--text-disabled);
}

/* ================================
 * Forced colors (Windows High Contrast)
 * ================================ */
@media (forced-colors: active) {
  .slider-thumb:focus-visible {
    outline: 2px solid ButtonText;
  }

  .slider-range {
    background-color: Highlight;
  }

  .slider-track {
    background-color: ButtonFace;
    border: 1px solid ButtonText;
  }

  .slider-thumb {
    background: ButtonText;
    border-color: ButtonText;
  }
}
